update ter_gateway
set online_status=#{gatewayOnlineStatus}

    ,diagnosis_update_time=#{gatewayDiagnosisUpdateTime}


    ,wifi_ssid=#{wifiSsid}


    ,channel=#{channel}


    ,rssi=#{gatewayRssi}

where sn = #{gateway}

update ter_info
set online_status = #{terOnlineStatus}

    ,rssi=#{terRssi}


    ,hop_count=#{hopCount}


    ,diagnosis_update_time=#{terDiagnosisUpdateTime}

where sn = #{terSn}

UPDATE ter_sensor_status SET data_status = CASE WHEN sensor_type IN
#{item}
THEN '1' ELSE '0' END, diagnosis_update_time = CASE WHEN sensor_type IN
#{item}
THEN now() ELSE diagnosis_update_time END where ter_sn = #{terSn}

UPDATE ter_sensor_extend_status SET data_status = CASE WHEN sensor_type IN
#{item}
THEN '1' ELSE '0' END, diagnosis_update_time = CASE WHEN sensor_type IN
#{item}
THEN now() ELSE diagnosis_update_time END where ter_sn = #{terSn}

